inline const DSS *GetDSS(const void *buf) {
  return ::flatbuffers::GetRoot<DSS>(buf);
}

inline const DSS *GetSizePrefixedDSS(const void *buf) {
  return ::flatbuffers::GetSizePrefixedRoot<DSS>(buf);
}

inline const char *DSSIdentifier() {
  return "$DSS";
}

inline bool DSSBufferHasIdentifier(const void *buf) {
  return ::flatbuffers::BufferHasIdentifier(
      buf, DSSIdentifier());
}

inline bool SizePrefixedDSSBufferHasIdentifier(const void *buf) {
  return ::flatbuffers::BufferHasIdentifier(
      buf, DSSIdentifier(), true);
}

template <bool B = false>
inline bool VerifyDSSBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifyBuffer<DSS>(DSSIdentifier());
}

template <bool B = false>
inline bool VerifySizePrefixedDSSBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifySizePrefixedBuffer<DSS>(DSSIdentifier());
}

inline void FinishDSSBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<DSS> root) {
  fbb.Finish(root, DSSIdentifier());
}

inline void FinishSizePrefixedDSSBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<DSS> root) {
  fbb.FinishSizePrefixed(root, DSSIdentifier());
}

